	@Test
	void legacyTupleStrategyUsesRetainedCountMinRuntimePath() throws Exception {
		PropertyState properties = PropertyState.capture(EXACT_LIMIT_PROPERTY, SKEW_RATIO_PROPERTY, ROW_BUDGET_PROPERTY,
				SAMPLE_SIZE_PROPERTY);
		try {
			properties.clearAll();
			RareOverlapFixture fixture = buildRareOverlapFixture(SketchBasedJoinEstimator.Config.defaults()
					.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.TUPLE)
					.withNominalEntries(512)
					.withSubjectBucketCount(128)
					.withPredicateBucketCount(128)
					.withObjectBucketCount(128)
					.withContextBucketCount(128)
					.withThrottleEveryN(1)
					.withThrottleMillis(0)
					.withRefreshSleepMillis(5)
					.withZeroIntersectionExactDistinctLimit(8)
					.withZeroIntersectionSkewRatio(32.0d)
					.withZeroIntersectionRowBudget(0L)
					.withZeroIntersectionSampleSize(32));

			assertEquals(SketchBasedJoinEstimator.SketchStrategy.COUNT_MIN_DUAL,
					fixture.estimator.getSketchStrategy());
		} finally {
			properties.restore();
		}
	}

	private static RareOverlapFixture buildRareOverlapFixture(SketchBasedJoinEstimator.Config config) throws Exception {
		IRI locatedAt = VF.createIRI("urn:locatedAt");
		IRI hasName = VF.createIRI("urn:hasName");
		int overlapBranches = 64;
		int copiesPerBranch = 4;

		for (int noiseSubjects = 4096; noiseSubjects <= 262144; noiseSubjects *= 2) {
			StubSketchStatementSource rareOverlapStore = new StubSketchStatementSource();
			populateRareOverlapData(rareOverlapStore, locatedAt, hasName, overlapBranches, copiesPerBranch,
					noiseSubjects);

			SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(rareOverlapStore, config);
			estimator.rebuild();

			return new RareOverlapFixture(estimator, rareOverlapJoin(locatedAt, hasName),
					overlapBranches * copiesPerBranch);
		}

		throw new AssertionError("Unable to construct a rare-overlap fixture");
	}

	private static void populateRareOverlapData(StubSketchStatementSource store, IRI locatedAt, IRI hasName,
			int overlapBranches,
			int copiesPerBranch, int noiseSubjects) {
		List<Resource> branches = new ArrayList<>(overlapBranches);
		for (int branchIndex = 0; branchIndex < overlapBranches; branchIndex++) {
			Resource branch = VF.createIRI("urn:branch:" + branchIndex);
			branches.add(branch);
			store.add(VF.createStatement(branch, hasName, VF.createLiteral("Branch " + branchIndex)));
			for (int copyIndex = 0; copyIndex < copiesPerBranch; copyIndex++) {
				Resource copy = VF.createIRI("urn:copy:" + branchIndex + ":" + copyIndex);
				store.add(VF.createStatement(copy, locatedAt, branch));
			}
		}

		for (int noiseIndex = 0; noiseIndex < noiseSubjects; noiseIndex++) {
			Resource noiseSubject = VF.createIRI("urn:noise:" + noiseIndex);
			store.add(VF.createStatement(noiseSubject, hasName, VF.createLiteral("Noise " + noiseIndex)));
		}
	}

	private static Join rareOverlapJoin(IRI locatedAt, IRI hasName) {
		return new Join(
				new StatementPattern(Var.of("copy"), Var.of("locatedAt", locatedAt), Var.of("branch")),
				new StatementPattern(Var.of("branch"), Var.of("hasName", hasName), Var.of("branchName")));
	}

	private static int intField(Object target, String name) throws Exception {
		Field field = target.getClass().getDeclaredField(name);
		field.setAccessible(true);
		return field.getInt(target);
	}

	private static int staticIntField(Class<?> target, String name) throws Exception {
		Field field = target.getDeclaredField(name);
		field.setAccessible(true);
		return field.getInt(null);
	}

