	private record PropertyState(String[] keys, String[] values) {

		private static PropertyState capture(String... keys) {
			String[] values = new String[keys.length];
			for (int i = 0; i < keys.length; i++) {
				values[i] = System.getProperty(keys[i]);
			}
			return new PropertyState(keys, values);
		}

		private void clearAll() {
			for (String key : keys) {
				System.clearProperty(key);
			}
		}

		private void restore() {
			for (int i = 0; i < keys.length; i++) {
				if (values[i] == null) {
					System.clearProperty(keys[i]);
				} else {
					System.setProperty(keys[i], values[i]);
				}
			}
		}
	}
